const e={id:"advanced-agents",name:"Advanced & Resistant Pathogen Agents",icon:"🛡",category:"Infectious Disease",overview:{definition:"Antimicrobial agents used primarily for multidrug-resistant (MDR), extensively drug-resistant (XDR), and pan-drug-resistant (PDR) organisms. Includes aminoglycosides for once-daily extended-interval dosing, novel beta-lactam/beta-lactamase inhibitor combinations, polymyxins, oxazolidinones, antifungals with extended-spectrum activity, and liposomal amphotericin B. These agents represent the last lines of defense against the most resistant organisms and require careful stewardship.",epidemiology:"MDR Gram-negative infections cause >700,000 deaths annually worldwide. ESKAPE pathogens (Enterococcus, Staph aureus, Klebsiella, Acinetobacter, Pseudomonas, Enterobacter) drive increasing resistance. Novel beta-lactam/BLI combinations have transformed treatment options for CRE and MDR Pseudomonas since 2014. Polymyxin use declining due to nephrotoxicity but remains critical for pan-resistant Acinetobacter.",keyGuidelines:[{name:"IDSA 2022 Guidance on Resistant Gram-Negative Infections",detail:"First IDSA guidance document specifically addressing CRE, ESBL-E, difficult-to-treat Pseudomonas, and carbapenem-resistant Acinetobacter baumannii. Defines preferred and alternative regimens for each resistance phenotype.",sourceIds:["idsa-2022-amr"]},{name:"ASHP/IDSA/SIDP 2020 Vancomycin Monitoring Consensus",detail:"Updated guidance recommending AUC-guided monitoring over trough-only. Target AUC/MIC 400–600 mg·h/L for S. aureus infections.",sourceIds:["ashp-idsa-pids-2020-vancomycin"]},{name:"IDSA 2016 Candidiasis Guidelines",detail:"Echinocandin first-line for candidemia. Defines step-down criteria to fluconazole. Liposomal AmB for azole-refractory or CNS disease.",sourceIds:["idsa-candidiasis"]},{name:"ESCMID-ECMM-ERS 2017 Aspergillosis Guideline",detail:"European guidance supporting voriconazole or isavuconazole as preferred therapy for invasive aspergillosis, with posaconazole primary prophylaxis in high-risk hematology patients.",sourceIds:["escmid-ecmm-ers-2017-aspergillosis"]}],landmarkTrials:[{name:"ASPECT-cUTI / ASPECT-NP Trials (Ceftolozane-Tazobactam)",detail:"Ceftolozane-tazobactam demonstrated efficacy across cUTI, cIAI (with metronidazole), and nosocomial pneumonia, including MDR Pseudomonas aeruginosa. These phase 3 programs anchored FDA approval and later resistant-pathogen positioning.",sourceIds:["aspect-cuti-ciai","aspect-np"]},{name:"RESTORE-IMI 1 & 2 (Imipenem-Cilastatin-Relebactam)",detail:"IMI-R superior to colistin + imipenem for CRE and MDR Pseudomonas in both cUTI/IAI and HAP/VAP. Established IC-R as a preferred option over polymyxins.",sourceIds:["restore-imi-1","restore-imi-2"]},{name:"ESTABLISH 1 & 2 Trials (Tedizolid)",detail:"Tedizolid 200mg QD × 6 days non-inferior to linezolid 600mg BID × 10 days for ABSSSI including MRSA. Shorter duration, once-daily dosing, potentially better tolerability.",sourceIds:["establish"]},{name:"Hartford Nomogram (Aminoglycosides)",detail:"Established 7 mg/kg extended-interval dosing for gentamicin/tobramycin. AUC-guided approach reduces nephrotoxicity while maintaining efficacy through concentration-dependent killing.",sourceIds:["hartford-nomogram"]}],riskFactors:"Prior antibiotic exposure (especially broad-spectrum), healthcare exposure, ICU admission, immunosuppression, solid organ or stem cell transplant, prolonged hospitalization, invasive devices, prior MDR organism isolation, travel to endemic regions."},subcategories:[{id:"cre-management",name:"Carbapenem-Resistant Enterobacteriaceae (CRE)",definition:"Enterobacteriaceae non-susceptible to at least one carbapenem (or producing carbapenemase). Includes KPC, NDM, OXA-48, VIM, IMP producers. One of the most critical AMR threats globally.",clinicalPresentation:"Any infection type: UTI, bacteremia, pneumonia, IAI. Suspect in patients with prior carbapenem exposure, healthcare contact in endemic regions, or prior MDR organism colonization.",diagnostics:"Culture and susceptibility testing essential. Carbapenemase PCR panel (KPC, NDM, OXA-48, VIM, IMP) guides therapy. MIC testing required — not just S/I/R breakpoints. Check ceftazidime-avibactam and meropenem-vaborbactam susceptibility. Consult ID and clinical pharmacy for complex cases.",rapidDiagnostics:[{trigger:"Carbapenemase testing identifies KPC",action:"Prioritize ceftazidime-avibactam or meropenem-vaborbactam and de-escalate away from polymyxin-based salvage if it was started empirically.",rationale:"Mechanism-specific therapy consistently outperforms older toxicity-heavy fallback regimens."},{trigger:"Carbapenemase testing identifies NDM, VIM, or IMP",action:"Do not continue any stand-alone beta-lactam/BLI product; move to ceftazidime-avibactam plus aztreonam or cefiderocol.",rationale:"MBL-producing CRE is the main place where a paired regimen changes whether aztreonam is viable."}],breakpointNotes:[{marker:"MIC-based interpretation",interpretation:"CRE therapy selection should be based on organism-specific MICs and carbapenemase mechanism, not on zone diameters or the generic 'CRE' label alone.",action:"Ask the lab for carbapenemase clarification and MIC details before finalizing definitive therapy."},{marker:"Ceftazidime-avibactam coverage gap",interpretation:"A susceptible ceftazidime-avibactam result is compatible with KPC or OXA-48, but not with stand-alone MBL activity.",action:"If an MBL is present, pair aztreonam or abandon the drug for a different anchor."}],intrinsicResistance:[{organism:"Proteus, Morganella, Providencia",resistance:"These genera retain intrinsic polymyxin limitations even when they also acquire carbapenemases.",implication:"Do not build salvage CRE regimens around colistin for these organisms."},{organism:"MBL-producing Enterobacterales",resistance:"Stand-alone avibactam, vaborbactam, and relebactam combinations remain functionally inactive against the metallo-beta-lactamase itself.",implication:"This is the main place where mechanism testing changes therapy immediately."}],coverageMatrix:[{label:"KPC-CRE",status:"preferred",detail:"Ceftazidime-avibactam or meropenem-vaborbactam are the primary anchors; imipenem-cilastatin-relebactam is another option when susceptible."},{label:"OXA-48-like CRE",status:"active",detail:"Ceftazidime-avibactam is usually the cleanest fit; meropenem-vaborbactam does not reliably solve this mechanism."},{label:"NDM, VIM, or IMP",status:"conditional",detail:"Use ceftazidime-avibactam plus aztreonam or cefiderocol rather than any stand-alone BL/BLI product."},{label:"Colistin monotherapy",status:"avoid",detail:"Reserve only for last-line salvage when better targeted options truly do not exist."}],durationGuidance:{standard:"7–14 days (source and severity dependent)",severe:"14 days (bacteremia) — repeat blood cultures at 48h",stewardshipNote:"IDSA 2022: Use targeted regimens based on carbapenemase type. KPC — ceftazidime-avibactam or meropenem-vaborbactam preferred. NDM — aztreonam-avibactam (investigational), ceftazidime-avibactam + aztreonam. Combination therapy only when synergy demonstrated."},empiricTherapy:[{line:"KPC-producing CRE",options:[{drug:"ceftazidime-avibactam",regimen:"Ceftazidime-Avibactam 2.5g IV q8h (adjust for renal function)",notes:"Preferred for KPC-CRE and OXA-48. Does NOT cover NDM. Check local susceptibility.",evidence:"A-II",evidenceSource:"IDSA 2022",monographId:"ceftazidime-avibactam",evidenceSourceIds:["idsa-2022-amr"],id:"advanced-agents/cre-management/kpc-producing-cre/ceftazidime-avibactam-1"},{drug:"meropenem-vaborbactam",regimen:"Meropenem-Vaborbactam 4g IV q8h (infuse over 3h)",notes:"Alternative for KPC-CRE. Does NOT cover NDM, OXA-48, or Acinetobacter.",evidence:"A-II",evidenceSource:"IDSA 2022",monographId:"meropenem-vaborbactam",evidenceSourceIds:["idsa-2022-amr"],id:"advanced-agents/cre-management/kpc-producing-cre/meropenem-vaborbactam-2"}]},{line:"NDM-producing CRE",options:[{drug:"ceftazidime-avibactam",regimen:"Ceftazidime-Avibactam 2.5g IV q8h + Aztreonam 2g IV q6h (extended infusion)",notes:"Combination required — CAZ-AVI restores aztreonam activity against MBL-producers. Ceftazidime-avibactam protects aztreonam from hydrolysis. ID consult mandatory.",evidence:"B-II",evidenceSource:"IDSA 2022",monographId:"ceftazidime-avibactam",evidenceSourceIds:["idsa-2022-amr"],id:"advanced-agents/cre-management/ndm-producing-cre/ceftazidime-avibactam-1"}]},{line:"Salvage / Pan-resistant",options:[{drug:"colistin",regimen:"Colistin (CMS) — load 9 MU IV, then 4.5 MU IV q12h (CrCl-adjusted), always in combination",notes:"Use only when all other options exhausted. Nephrotoxicity in 30-50%. Never monotherapy. Combination with meropenem, rifampin, or fosfomycin based on MIC data.",evidence:"C-III",evidenceSource:"IDSA 2022",monographId:"colistin",evidenceSourceIds:["idsa-2022-amr"],id:"advanced-agents/cre-management/salvage-pan-resistant/colistin-1"}]}],pearls:["Never use ceftazidime-avibactam monotherapy for NDM-producers — avibactam does NOT inhibit metallo-beta-lactamases. This is a potentially fatal prescribing error.","MIC testing is mandatory before treating CRE — zone diameter breakpoints are unreliable. Use broth microdilution.","Consult ID and clinical pharmacy for all CRE infections — outcomes are significantly better with specialist involvement.","Check the IDSA 2022 AMR guidance table — treatment choice depends on which carbapenemase is present."]},{id:"mdr-pseudomonas",name:"Difficult-to-Treat Pseudomonas aeruginosa (DTR-PA)",definition:"Pseudomonas non-susceptible to all first-line agents: piperacillin-tazobactam, cefepime, ceftazidime, meropenem, imipenem, aztreonam, AND ciprofloxacin/levofloxacin. Growing global problem.",clinicalPresentation:"VAP, HAP, bacteremia, complicated UTI, wound infections. ICU patients, CF patients, prior antibiotic exposure at high risk.",diagnostics:"Full susceptibility panel required. Test ceftolozane-tazobactam, imipenem-cilastatin-relebactam, ceftazidime-avibactam. CF patients require special testing (agar dilution).",rapidDiagnostics:[{trigger:"Traditional anti-pseudomonal beta-lactams all report non-susceptible",action:"Use the novel anti-pseudomonal panel and prior-exposure history to choose ceftolozane-tazobactam or imipenem-cilastatin-relebactam rather than defaulting to colistin.",rationale:"Most modern DTR Pseudomonas cases can now avoid polymyxin toxicity if susceptibility testing is available."},{trigger:"MBL signal or carbapenemase PCR suggests VIM or IMP",action:"Treat ceftolozane-tazobactam and ceftazidime-avibactam as unreliable and pivot toward cefiderocol-centered therapy.",rationale:"MBL-producing Pseudomonas is a distinct subgroup with a much smaller active-agent shortlist."}],breakpointNotes:[{marker:"Ceftolozane-tazobactam dosing",interpretation:"The pneumonia or serious-infection dose is 3 g q8h; lower cUTI/cIAI dosing is insufficient for invasive DTR Pseudomonas.",action:"Do not reuse the smaller dose in bacteremia or pneumonia because it undercuts the advantage of the drug."},{marker:"Traditional beta-lactam still susceptible",interpretation:"If cefepime, meropenem, or piperacillin-tazobactam remains susceptible, optimized extended-infusion use still outranks a reflex jump to a reserve agent.",action:"Verify whether the case is truly DTR before spending a newer beta-lactam."}],intrinsicResistance:[{organism:"Pseudomonas aeruginosa",resistance:"Baseline low permeability and inducible AmpC make borderline exposures fail and select resistance quickly.",implication:"PK/PD optimization is not optional when treating MDR or DTR isolates."},{organism:"MBL-producing Pseudomonas",resistance:"Ceftolozane-tazobactam and ceftazidime-avibactam lose activity despite the broad DTR label.",implication:"Mechanism-aware escalation remains essential even after the phenotype is called resistant."}],coverageMatrix:[{label:"No MBL detected",status:"preferred",detail:"Ceftolozane-tazobactam or imipenem-cilastatin-relebactam are common first-look agents when susceptible."},{label:"MBL detected",status:"avoid",detail:"Do not rely on ceftolozane-tazobactam or ceftazidime-avibactam as the primary anchor."},{label:"Traditional cefepime or meropenem still active",status:"active",detail:"Use high-dose extended infusion of the active traditional agent before escalating."},{label:"Polymyxin fallback",status:"conditional",detail:"Keep as salvage only when novel-agent susceptibility or access is absent."}],durationGuidance:{standard:"7 days (HAP/VAP per IDSA/ATS 2016)",severe:"14 days (bacteremia, inadequate source control)",stewardshipNote:"Combination therapy no longer recommended for DTR-PA in most cases when susceptible to novel agents. ID consult mandatory."},empiricTherapy:[{line:"Preferred (DTR-PA)",options:[{drug:"ceftolozane-tazobactam",regimen:"Ceftolozane-Tazobactam 3g IV q8h (HAP/VAP: 1.5g q8h for cUTI/IAI) — standard infusion 1h",notes:"Excellent anti-pseudomonal activity. Stable against most Pseudomonas resistance mechanisms except MBL.",evidence:"A-II",evidenceSource:"IDSA 2022",monographId:"ceftolozane-tazobactam",evidenceSourceIds:["idsa-2022-amr"],id:"advanced-agents/mdr-pseudomonas/preferred-dtr-pa/ceftolozane-tazobactam-1"},{drug:"imipenem-cilastatin-relebactam",regimen:"Imipenem-Cilastatin-Relebactam 1.25g IV q6h (infuse over 30 min)",notes:"Active against KPC and AmpC producers. Restores imipenem activity. RESTORE-IMI trials support use.",evidence:"A-II",evidenceSource:"IDSA 2022",monographId:"imipenem-cilastatin-relebactam",evidenceSourceIds:["idsa-2022-amr"],id:"advanced-agents/mdr-pseudomonas/preferred-dtr-pa/imipenem-cilastatin-relebactam-2"}]}],pearls:["Ceftolozane-tazobactam is NOT active against ESBL-producing Enterobacteriaceae or KPC-CRE.","Imipenem-cilastatin-relebactam does NOT cover NDM-producers or Acinetobacter.","For CF patients with chronic Pseudomonas, susceptibility testing with agar dilution may give more reliable results than automated systems.","Always obtain ID consultation for DTR-PA infections — mortality is significantly higher without appropriate therapy."]}],drugMonographs:[{id:"gentamicin",name:"Gentamicin",brandNames:"Garamycin",drugClass:"Aminoglycoside",mechanismOfAction:"Binds irreversibly to the 30S ribosomal subunit (16S rRNA), causing misreading of mRNA and premature chain termination. Uptake into bacterial cell is dependent on electron transport chain (aerobic organisms only). Concentration-dependent bactericidal activity.",spectrum:"Gram-negative: Excellent against Enterobacteriaceae (E. coli, Klebsiella, Enterobacter, Serratia, Proteus), Pseudomonas aeruginosa. Gram-positive: Synergy with cell wall-active agents (penicillin/vancomycin) for Enterococcus and Staphylococcus endocarditis. GAPS: Anaerobes, Streptococci (intrinsic resistance), Stenotrophomonas. Increasing resistance in MDR gram-negatives.",dosing:{extended_interval:"7 mg/kg IV q24h (Hartford Nomogram) — use IBW if non-obese; AdjBW if obese",synergy_endocarditis:"1 mg/kg IV q8h (MSSA/Enterococcal endocarditis synergy dosing)",traditional:"1.7 mg/kg IV q8h (conventional dosing — monitor troughs <2 mg/L)",intrathecal:"4–8 mg IT q24h (gram-negative meningitis, adjunct to IV therapy)"},renalAdjustment:"Extended interval: CrCl 40-59 → q36h; CrCl 20-39 → q48h; CrCl <20 → conventional dosing recommended; HD/PD → dose post-dialysis, redose based on levels. Monitor levels regardless of interval. Use clinical pharmacokinetics service for complex cases.",hepaticAdjustment:"No hepatic adjustment needed. Gentamicin is eliminated unchanged by kidneys. However, hepatic disease is often associated with altered Vd — consult PK service.",adverseEffects:{common:"Nephrotoxicity (proximal tubule injury, ATN with prolonged use or trough accumulation), ototoxicity (cochlear — high-frequency hearing loss initially; vestibular — ataxia, oscillopsia)",serious:"Permanent sensorineural hearing loss (cochlear), irreversible vestibular toxicity, acute tubular necrosis, neuromuscular blockade (rare, high doses)",rare:"Neuromuscular blockade (avoid in myasthenia gravis), fetal ototoxicity with in-utero exposure",fdaBoxedWarnings:"Nephrotoxicity and ototoxicity. Risk increased with prolonged therapy, high doses, renal impairment, and concurrent nephrotoxins. Irreversible ototoxicity can occur without warning."},drugInteractions:["Vancomycin — additive nephrotoxicity; avoid concurrent use when possible; if necessary monitor renal function daily","Loop diuretics (furosemide, ethacrynic acid) — additive ototoxicity; ethacrynic acid most hazardous","Amphotericin B — additive nephrotoxicity","Cisplatin — additive nephrotoxicity and ototoxicity","Neuromuscular blocking agents — potentiation of blockade","NSAIDs — reduce renal prostaglandin-mediated afferent arteriole dilation, increase nephrotoxicity risk","Cyclosporine/tacrolimus — additive nephrotoxicity in transplant patients"],monitoring:"Extended interval: obtain random level 6–14h post-infusion; plot on Hartford Nomogram for interval selection. Traditional: peak 5–10 mg/L (drawn 30 min post-infusion), trough <2 mg/L (drawn 30 min pre-dose). Serum creatinine 2–3×/week. Audiology if prolonged therapy. Urine output monitoring.",pregnancyLactation:"Category D. Aminoglycosides cross the placenta. Fetal ototoxicity reported with streptomycin (less data with gentamicin, but theoretical risk same class). Avoid unless life-threatening infection with no alternatives. Minimal excretion in breast milk — oral absorption poor, low systemic risk for infant.",pkpdDriver:{driver:"Concentration-dependent (Cmax/MIC)",target:"Cmax/MIC ≥8–10 (extended interval); AUC/MIC ≥70–100 for synergy dosing",extendedInfusion:"NOT applicable — give as 30–60 min IV infusion to achieve high Cmax"},opatEligibility:{eligible:"conditional",administration:"Once-daily extended-interval dosing can work in OPAT when reliable drug-level follow-up is available.",monitoring:"Levels plus renal function are mandatory, often more than once weekly early in therapy.",considerations:["Appropriate only when the microbiology gain is real and home monitoring can keep up.","Poor OPAT choice when kidney function is unstable or synergy duration is already nearly complete."]},pharmacistPearls:["The Hartford Nomogram was designed for GENTAMICIN specifically. The 7 mg/kg dose with nomogram-guided intervals has equivalent efficacy and LESS nephrotoxicity than traditional dosing in most patients.","Use IBW for dosing in non-obese patients. Use AdjBW [IBW + 0.4×(TBW–IBW)] if obese (TBW >1.25×IBW). Using TBW in obese patients overdoses dramatically.","Extended-interval dosing uses the principle of concentration-dependent killing + post-antibiotic effect (PAE). Once you achieve Cmax/MIC ≥10, a drug-free interval actually enhances killing.","Conventional dosing (1.7 mg/kg q8h) is ONLY indicated for endocarditis synergy dosing and possibly Enterococcal infections — most other indications benefit from extended interval.","Trough level monitoring for conventional dosing must be drawn 30 min BEFORE the dose, not during infusion or too early after dose.","Nephrotoxicity is dose-cumulative and predictable — highest risk with troughs >2 mg/L, prolonged courses (>14 days), and concurrent nephrotoxins. It is usually reversible.","Ototoxicity can be cochlear (hearing loss, tinnitus) OR vestibular (balance, oscillopsia). Vestibular toxicity is often missed — ask about balance problems specifically."],dosingByIndication:[{label:"Serious gram-negative infection",regimen:"5-7 mg/kg IV q24h using extended-interval dosing",notes:"Reserve monotherapy for carefully selected urinary syndromes or when susceptibilities truly support it."},{label:"Synergy for endocarditis or enterococcal infection",regimen:"1 mg/kg IV q8h or institution-specific synergy protocol",notes:"Short-course synergy is a niche use case, not a routine add-on."}],renalReplacement:[{modality:"HD",guidance:"Use post-hemodialysis dosing with level-guided redosing because missing the post-HD level or dose creates both toxicity and failure risk."},{modality:"CRRT",guidance:"CRRT aminoglycoside dosing is level-driven; use larger loading doses but let measured levels determine the interval."}],specialPopulations:[{population:"Obesity",guidance:"Use adjusted body weight for dosing rather than actual body weight unless your local protocol says otherwise."},{population:"Pre-existing renal dysfunction or vestibular injury risk",guidance:"The toxicity margin is narrow enough that alternative agents should be preferred whenever they remain active."}],therapeuticDrugMonitoring:{target:"Extended-interval peaks should be high enough for concentration-dependent killing while troughs fall low enough to limit toxicity; synergy regimens target low troughs and modest peaks.",sampling:"Use institution-specific nomograms or measured peaks and troughs; timing accuracy matters as much as the result.",adjustment:"If kidney function is worsening or levels stay prolonged, stop gentamicin rather than forcing the interval when another active drug exists."},administration:{infusion:"Usually infused over about 30 minutes with careful level timing documentation.",compatibility:"Do not co-infuse in the same line or bag with beta-lactams because inactivation can occur.",note:"The loading dose is important even in renal dysfunction because underloading is a common stewardship failure."},ivToPoSwitch:{poBioavailability:"No oral systemic formulation exists.",switchCriteria:"Transition to an active oral or safer IV agent as soon as susceptibilities allow because gentamicin is rarely the ideal full-course drug.",note:"If the only reason gentamicin is present is synergy, set a stop date early."},interactionActions:[{interactingAgent:"Loop diuretics",effect:"Can amplify ototoxicity and complicate renal toxicity assessment.",management:"Avoid the combination when possible and monitor hearing and kidney function closely if it cannot be avoided.",severity:"major"},{interactingAgent:"Vancomycin, amphotericin B, or other nephrotoxins",effect:"Additive kidney injury is common and often avoidable.",management:"Keep overlap as short as possible and increase lab and level surveillance.",severity:"major"}],stewardshipUseCases:[{scenario:"Short targeted gram-negative therapy or salvage regimen component",role:"Aminoglycosides earn their place when concentration-dependent killing or limited susceptibility leaves few better options.",notes:"They should not be routine double-coverage decorations on top of an active beta-lactam."},{scenario:"Synergy in selected endocarditis pathways",role:"Useful only in specific guideline-backed circumstances and for defined durations.",notes:"Write the planned stop date at the time the drug is started."}],penetration:[{site:"Urine / renal cortex",detail:"Very high urinary and renal cortical concentrations support pyelonephritis and gram-negative urinary-source synergy strategies."},{site:"Lung",detail:"Pulmonary penetration is poor, which is why gentamicin should not be relied on as pneumonia monotherapy."},{site:"CSF",detail:"Systemic CSF penetration is minimal; CNS use generally requires intrathecal or intraventricular administration if it is used at all."}]},{id:"aztreonam",name:"Aztreonam",brandNames:"Azactam",drugClass:"Monobactam (beta-lactam antibiotic)",mechanismOfAction:"Binds specifically to penicillin-binding protein 3 (PBP3) of aerobic gram-negative bacteria. Inhibits cell wall peptidoglycan synthesis, leading to cell lysis. Unique structure with a monocyclic beta-lactam ring — no cross-reactivity with penicillins or cephalosporins in terms of the ring system.",spectrum:"Exclusively aerobic gram-negative: E. coli, Klebsiella, Proteus, Serratia, Pseudomonas aeruginosa, Haemophilus, Neisseria. ZERO gram-positive activity. ZERO anaerobic activity. Key advantage: no cross-allergenicity with penicillins/carbapenems (different ring structure). Cross-reactivity with ceftazidime (identical R1 side chain) — avoid if ceftazidime allergy.",dosing:{standard:"1–2g IV/IM q8h",severe:"2g IV q6h (severe gram-negative infections, Pseudomonas)",cystic_fibrosis:"2g IV q6–8h (aggressive dosing for CF exacerbations)",inhalation:"75mg inhaled TID (Cayston — for CF/Pseudomonas chronic suppression)"},renalAdjustment:"CrCl 10–30: reduce by 50% (standard dose q8h → q12h or half dose). CrCl <10: 25% of usual dose. HD: supplemental dose post-dialysis. No active metabolites.",hepaticAdjustment:"Mild-moderate hepatic disease: no adjustment. Severe hepatic dysfunction: reduce dose by 20-25%. Aztreonam excreted primarily renally but partially metabolized.",adverseEffects:{common:"Local site reactions (IV/IM), rash (typically morbilliform), nausea, diarrhea",serious:"C. difficile colitis (all antibiotics), hepatotoxicity (rare), phlebitis",rare:"Seizures (extremely rare at standard doses), severe rash"},drugInteractions:["Furosemide, probenecid — increase aztreonam serum levels (competitive tubular secretion)","Imipenem — potential antagonism if used together (in-vitro) — separate if combination needed","Ceftazidime-avibactam — SYNERGISTIC combination for NDM-CRE: CAZ-AVI protects aztreonam from MBL hydrolysis while aztreonam provides bactericidal activity"],monitoring:"Renal function (primary elimination). CBC, LFTs for prolonged courses. C. diff monitoring for diarrhea.",pregnancyLactation:"Category B. No teratogenicity in animal studies. Limited human data. Use only if benefit outweighs risk. Minimal excretion in breast milk.",rapidDiagnostics:[{trigger:"NDM, VIM, or IMP is confirmed",action:"Pair aztreonam with an avibactam-containing regimen such as ceftazidime-avibactam rather than using aztreonam alone.",rationale:"Aztreonam survives the MBL, but co-produced serine beta-lactamases usually still need to be blocked."},{trigger:"Severe beta-lactam allergy requires a gram-negative-only option",action:"Aztreonam remains useful, but verify whether gram-positive or anaerobic add-on coverage is also needed.",rationale:"Its allergy advantage can obscure the fact that it leaves obvious spectrum gaps."}],breakpointNotes:[{marker:"Aztreonam susceptibility in MBL producers",interpretation:"Aztreonam alone can look active in vitro while still failing clinically if co-produced ESBL or AmpC enzymes are present.",action:"Treat aztreonam monotherapy as unreliable in serious MBL infection unless a paired avibactam strategy is in place."},{marker:"Ceftazidime side-chain cross-reactivity",interpretation:"The ring system is unique, but the shared R1 side chain means immediate ceftazidime allergy still matters.",action:"Do not assume aztreonam is universally safe in all cephalosporin-allergic patients."}],intrinsicResistance:[{organism:"Gram-positive organisms and anaerobes",resistance:"Aztreonam has no clinically useful activity against these groups.",implication:"Always assess whether companion coverage is required."},{organism:"Stenotrophomonas maltophilia",resistance:"Aztreonam alone is not dependable because the organism's L2 beta-lactamase can still hydrolyze it unless avibactam is present.",implication:"Keep aztreonam inside a mechanism-aware combination rather than using it as monotherapy."}],coverageMatrix:[{label:"MBL-CRE with avibactam partner",status:"conditional",detail:"A high-value component of ceftazidime-avibactam plus aztreonam strategies."},{label:"Aerobic gram-negative infection with severe penicillin allergy",status:"active",detail:"Often the cleanest beta-lactam option if the pathogen is susceptible."},{label:"Gram-positive or anaerobic infection",status:"avoid",detail:"No dependable coverage."},{label:"Aztreonam monotherapy for MBL infection",status:"avoid",detail:"Do not rely on it without an avibactam-containing partner."}],ivToPoSwitch:{poBioavailability:"No oral formulation exists, so step-down requires switching to another active oral class.",switchCriteria:"Leave aztreonam once allergy clarification or susceptibilities reveal a better IV or oral option.",note:"Its main value is often as a bridge while allergy and microbiology are clarified."},opatEligibility:{eligible:"conditional",administration:"OPAT is feasible, but q8h dosing and the need for partner agents can make it more complex than it first appears.",monitoring:"Weekly CBC and renal function are minimum expectations, with closer review if combination therapy is being used for resistant pathogens.",considerations:["Most useful when a severe beta-lactam allergy truly prevents easier options.","Do not build OPAT around aztreonam monotherapy for MBL organisms."]},pharmacistPearls:["Aztreonam is the antibiotic of choice for serious gram-negative infections in patients with severe penicillin/carbapenem allergy. However, it does NOT cover gram-positives or anaerobes — ensure adequate coverage for those.","Ceftazidime allergy DOES cross-react with aztreonam (identical R1 side chain on both molecules). This is one of the few true cross-reactions between different beta-lactam classes.","Aztreonam + ceftazidime-avibactam is a powerful combination for NDM-producing CRE: avibactam protects aztreonam from metallo-beta-lactamase hydrolysis.","Aztreonam does NOT cause positive results on beta-lactam skin testing in most penicillin-allergic patients. However, if concerned, refer to allergy for evaluation.","Aztreonam has no activity against gram-positive organisms. A common clinical error is treating gram-positive bacteremia with aztreonam based on susceptibility report — aztreonam is not indicated."],dosingByIndication:[{label:"Aerobic gram-negative infection with severe beta-lactam allergy",regimen:"1-2 g IV q8h",notes:"Use higher-end dosing for severe infection or Pseudomonas risk, but remember the gram-positive and anaerobic gaps."},{label:"Serious gram-negative or Pseudomonas infection",regimen:"2 g IV q6-8h",notes:"Only trust monotherapy when the organism and syndrome truly fit aztreonam's narrow spectrum."}],renalReplacement:[{modality:"HD",guidance:"Use renally adjusted dosing with a post-hemodialysis supplement because aztreonam is primarily renally cleared."},{modality:"CRRT",guidance:"CRRT often still supports q8h or more aggressive exposure, particularly when resistant gram-negative infection is being treated."}],specialPopulations:[{population:"Immediate ceftazidime allergy",guidance:"Do not assume aztreonam is automatically safe because the shared side chain with ceftazidime still matters."},{population:"MBL-producing CRE or polymicrobial infection",guidance:"Its narrow allergy-friendly profile is useful, but only if you explicitly solve the co-produced beta-lactamase or companion-coverage gap."}],therapeuticDrugMonitoring:{target:"No routine serum target; the important target is dependable gram-negative coverage without forgetting the obvious spectrum gaps.",sampling:"No drug levels are standard. Review renal function, organism phenotype, and partner-drug adequacy.",adjustment:"If the organism is an MBL producer, fix the partner strategy rather than just pushing aztreonam harder."},administration:{infusion:"Typically infused intermittently on a q6-8h schedule depending on syndrome severity.",note:"Operational simplicity should not hide the need for additional gram-positive or anaerobic coverage when required."},interactionActions:[{interactingAgent:"Ceftazidime-avibactam",effect:"The combination can restore clinical usefulness against MBL organisms where aztreonam alone is unreliable.",management:"Pair intentionally for NDM, VIM, or IMP producers when the mechanism demands it.",severity:"major"},{interactingAgent:"Probenecid",effect:"Can raise aztreonam levels by reducing renal tubular secretion.",management:"Avoid using probenecid as a pseudo-boosting strategy.",severity:"monitor"}],stewardshipUseCases:[{scenario:"Serious gram-negative therapy in true beta-lactam allergy",role:"A valuable narrow-spectrum bridge when allergy limits other beta-lactams.",notes:"Always reassess whether the allergy history still justifies it."},{scenario:"Mechanism-aware partner in MBL regimens",role:"Useful when paired correctly rather than used alone against a resistant phenotype it cannot reliably solve.",notes:"Document the pairing rationale clearly for the next team."}],monitoringActions:[{trigger:"Rapid diagnostics or carbapenemase testing points to NDM, VIM, or IMP production",action:"Make sure the ceftazidime-avibactam partner is active and scheduled correctly rather than assuming aztreonam monotherapy has become adequate.",rationale:"The main preventable failure mode is treating the MBL label with aztreonam alone.",sourceIds:["idsa-2024-amr","aztreonam-avibactam-evidence","clsi-breakpoint-updates"]},{trigger:"Allergy clarification suggests broader beta-lactams are actually usable",action:"Reassess the need for aztreonam the same day and de-escalate if a better-supported beta-lactam can be used safely.",sourceIds:["idsa-2024-amr"]}],misuseTraps:[{scenario:"Using aztreonam alone for an MBL-producing isolate because the susceptibility report appears permissive",risk:"Co-produced serine beta-lactamases can still inactivate aztreonam and create a false sense of definitive coverage.",saferApproach:"Pair with ceftazidime-avibactam or use another mechanism-directed regimen when MBL biology is present.",sourceIds:["idsa-2024-amr","aztreonam-avibactam-evidence","clsi-breakpoint-updates"]},{scenario:"Assuming aztreonam is automatically safe in a patient with immediate ceftazidime allergy",risk:"The shared side chain can make the allergy workaround unsafe as well as ineffective.",saferApproach:"Review the exact allergy history and use supervised testing or an alternative plan when ceftazidime reactivity is plausible.",sourceIds:["idsa-2024-amr"]}],administrationConstraints:[{title:"MBL regimens need aztreonam and ceftazidime-avibactam coordinated intentionally",detail:"The combination fails operationally when one agent is timed, adjusted, or handed off independently of the other.",action:"Link the two drugs in the medication plan and verify combination-testing interpretation in the stewardship note.",sourceIds:["idsa-2024-amr","aztreonam-avibactam-evidence","clsi-breakpoint-updates"]},{title:"Spectrum gaps should be named, not assumed covered by momentum",detail:"Aztreonam does not solve anaerobic or gram-positive needs in polymicrobial syndromes even when the gram-negative target is clear.",action:"Write the companion-coverage plan explicitly at initiation and reassessment.",sourceIds:["idsa-2024-amr"]}],siteSpecificAvoidances:[{site:"Polymicrobial intra-abdominal or aspiration infection without explicit companion coverage",reason:"Aztreonam leaves important anaerobic and gram-positive gaps that can be missed when allergy concerns dominate the plan.",preferredApproach:"Add the needed companion agents or use a broader regimen once allergy clarification allows it.",sourceIds:["idsa-2024-amr"]}],penetration:[{site:"Urine",detail:"Strong urinary exposure supports aztreonam use in susceptible gram-negative UTI when beta-lactam allergy limits options."},{site:"Lung",detail:"Pulmonary penetration is usable for gram-negative pneumonia, though it usually functions as a targeted niche agent rather than a broad empiric anchor."},{site:"CSF",detail:"Inflamed meninges allow some CSF entry, but aztreonam is not the usual first-line CNS beta-lactam."}]},{id:"ceftolozane-tazobactam",name:"Ceftolozane-Tazobactam",brandNames:"Zerbaxa",drugClass:"5th-generation cephalosporin / beta-lactamase inhibitor combination",mechanismOfAction:"Ceftolozane (novel cephalosporin with modified R1 side chain) binds multiple PBPs in Pseudomonas aeruginosa with high affinity. Tazobactam inhibits class A and some class C beta-lactamases. The unique structure evades many Pseudomonas resistance mechanisms (efflux pumps, porin loss). Does NOT inhibit class B (metallo-BLI) or class D (OXA) beta-lactamases.",spectrum:"Outstanding Pseudomonas aeruginosa activity (including many MDR strains). Good Enterobacteriaceae (including ESBL-producers — tazobactam inhibits ESBL). Weak anaerobic coverage. NO MRSA. NO Acinetobacter. NO CRE (carbapenem-resistant). Stenotrophomomas variable.",dosing:{cuti_iai:"1.5g (1g ceftolozane/0.5g tazobactam) IV q8h",hap_vap:"3g (2g/1g) IV q8h (higher dose for pulmonary infections)",adjustment_note:"Dose based on CrCl — see renal adjustment"},renalAdjustment:"CrCl 30–50: 750mg q8h (for cUTI/IAI) or 1.5g q8h (HAP/VAP). CrCl 15–29: 375mg q8h or 750mg q8h. CrCl <15/HD: supplemental dose post-HD. Consult package insert or clinical pharmacist — complex renal dosing.",hepaticAdjustment:"No hepatic dose adjustment required.",adverseEffects:{common:"Nausea, diarrhea, headache, fever, hypokalemia (tazobactam component)",serious:"C. difficile colitis, hepatotoxicity (rare), thrombocytosis",rare:"Hypersensitivity, seizures (rare)",contraindications:"Severe hypersensitivity to cephalosporins or piperacillin-tazobactam."},drugInteractions:["Probenecid — increases ceftolozane exposure (blocks tubular secretion) — avoid combination","No significant CYP450 interactions"],monitoring:"Renal function (adjust dose). C. diff monitoring. CBC, LFTs for prolonged courses.",pregnancyLactation:"Category not assigned (post-2014 FDA labeling). No adequate human data. Animal studies showed no adverse effects. Use only when benefit outweighs risk.",pkpdDriver:{driver:"Time-dependent (T>MIC)",target:"fT>MIC ≥40–70% (free drug time above MIC)",extendedInfusion:"Consider extended infusion (1h standard; 3h for higher MIC targets or severe infections) — increases fT>MIC"},rapidDiagnostics:[{trigger:"True DTR Pseudomonas is confirmed without an MBL signal",action:"Ceftolozane-tazobactam becomes a frontline option, especially when local susceptibility favors it over ceftazidime-avibactam.",rationale:"It is one of the most Pseudomonas-focused reserve beta-lactams in the toolkit."},{trigger:"VIM or IMP is detected",action:"Move away from ceftolozane-tazobactam because the drug does not solve metallo-beta-lactamase-mediated resistance.",rationale:"A resistant phenotype alone can obscure the specific mechanism that closes this option."}],breakpointNotes:[{marker:"Dose selection by syndrome",interpretation:"The 3 g q8h exposure is the serious-infection or pulmonary dose; 1.5 g q8h is the smaller cUTI/cIAI dose.",action:"Do not use the smaller dose for bacteremia or pneumonia just because the isolate is urinary in origin."},{marker:"Extended infusion for higher MIC isolates",interpretation:"Longer infusion materially improves target attainment when the Pseudomonas MIC is creeping upward.",action:"Coordinate with pharmacy rather than defaulting to a short infusion out of habit."}],intrinsicResistance:[{organism:"MBL-producing gram-negatives",resistance:"Tazobactam does not inhibit NDM, VIM, or IMP.",implication:"Do not use ceftolozane-tazobactam when an MBL is established."},{organism:"CRAB and most CRE phenotypes",resistance:"The drug is not a dependable rescue option for Acinetobacter or carbapenemase-producing Enterobacterales.",implication:"Keep it focused on resistant Pseudomonas rather than 'broad MDR' use."}],coverageMatrix:[{label:"DTR Pseudomonas without MBL",status:"preferred",detail:"A frontline reserve agent when susceptibility and site support it."},{label:"ESBL-E without Pseudomonas need",status:"conditional",detail:"Can be active, but stewardship usually prefers preserving the drug for resistant Pseudomonas."},{label:"MBL-producing isolates",status:"avoid",detail:"No dependable activity against NDM, VIM, or IMP."},{label:"CRE or CRAB",status:"inactive",detail:"Not the right reserve beta-lactam for these phenotypes."}],opatEligibility:{eligible:"conditional",administration:"Home or facility q8h prolonged infusion is feasible but operationally heavier than standard OPAT drugs.",monitoring:"Weekly CBC and renal function are minimum expectations, with closer review for prolonged therapy or unstable renal function.",considerations:["Best for stable patients with confirmed susceptible resistant Pseudomonas and no oral exit.","Avoid if stewardship follow-up cannot support a reserve-agent OPAT plan."]},pharmacistPearls:["Ceftolozane-tazobactam is specifically designed for MDR Pseudomonas aeruginosa — it is NOT the right drug for ESBL Klebsiella (use ertapenem) or CRE (use ceftazidime-avibactam).","The HAP/VAP dose (3g q8h) is DOUBLE the cUTI/IAI dose (1.5g q8h). This is because pulmonary PK/PD modeling requires higher exposures. Common prescribing error: using the lower dose for pneumonia.","Does NOT inhibit metallo-beta-lactamases (NDM, VIM, IMP) — if MBL suspected, this drug will fail.","Extended infusion over 3 hours significantly improves pharmacodynamic target attainment for Pseudomonas strains with MIC ≥4 mg/L. Work with clinical pharmacy to implement.","Resistance during therapy has been reported — obtain follow-up cultures if patient fails to respond."],dosingByIndication:[{label:"MDR or DTR Pseudomonas pneumonia",regimen:"3 g IV q8h over 3 hours",notes:"Use the pneumonia dose when lung infection or severe bacteremia is the reason you chose it."},{label:"Complicated UTI or intra-abdominal infection",regimen:"1.5-3 g IV q8h over 1-3 hours depending on syndrome and site",notes:"The lung dose is still favored when there is any question about severity or borderline susceptibility."}],renalReplacement:[{modality:"HD",guidance:"Use the renally adjusted regimen after hemodialysis; underdosing after dialysis is a common avoidable problem."},{modality:"CRRT",guidance:"CRRT often still supports aggressive q8h exposure, particularly when resistant Pseudomonas pneumonia is the target."}],specialPopulations:[{population:"Augmented renal clearance",guidance:"ARC is common in ICU pneumonia and can meaningfully lower exposure, so keep the prolonged infusion and full q8h schedule when renal function is brisk."},{population:"Metallo-beta-lactamase producers",guidance:"Do not use ceftolozane-tazobactam when MBL biology is established because the tazobactam partner does not solve that mechanism."}],therapeuticDrugMonitoring:{target:"No routine serum target; the main goal is full q8h prolonged-infusion exposure against the confirmed susceptible phenotype.",sampling:"Drug levels are not standard. Review susceptibility mechanism, infusion timing, and renal trajectory.",adjustment:"If it appears to be failing, re-check whether the organism truly fits the drug before escalating to more toxic salvage."},administration:{infusion:"Extended infusion over 3 hours is preferred for severe infection and resistant Pseudomonas.",stability:"OPAT and elastomeric use depend on local stability confirmation.",note:"This drug is at its best when it is used specifically for the Pseudomonas problem it was built to solve."},ivToPoSwitch:{poBioavailability:"No oral formulation exists.",switchCriteria:"Transition off IV therapy only if cultures later reveal an active oral option, which is uncommon in the resistant syndromes that justify use.",note:"Most discharge planning is infusion-based rather than PO conversion."},interactionActions:[{interactingAgent:"Warfarin",effect:"INR can shift during prolonged broad-spectrum treatment.",management:"Increase INR monitoring during therapy transitions.",severity:"monitor"},{interactingAgent:"Aminoglycosides",effect:"Combination may be intentional in salvage therapy, but line compatibility and additive kidney injury can become the operational problem.",management:"Use separate lines when possible and justify the duration of overlap explicitly.",severity:"monitor"}],stewardshipUseCases:[{scenario:"Definitive MDR Pseudomonas therapy",role:"A high-value reserve antipseudomonal when the phenotype matches and older beta-lactams do not.",notes:'It should not be used as a generic "big gun" for Enterobacterales.'},{scenario:"Avoiding colistin for susceptible resistant Pseudomonas",role:"Often the cleaner definitive option when susceptibility supports it.",notes:"Leave it on the shelf when standard cefepime or meropenem still works."}],monitoringActions:[{trigger:"Renal function shifts or a 3 g pneumonia regimen is not being maintained in lung infection",action:"Correct the dose and infusion strategy the same day rather than accepting lower-exposure carryover from non-pneumonia workflows.",rationale:"The main preventable failure mode is underdelivering the lung-focused regimen when resistant Pseudomonas is the target.",sourceIds:["idsa-2024-amr","aspect-np"]},{trigger:"Rapid diagnostics or phenotyping suggests MBL or non-Pseudomonas carbapenemase biology",action:"Reassess immediately because ceftolozane-tazobactam is not meant to rescue mechanism mismatches.",sourceIds:["idsa-2024-amr","aspect-np"]}],misuseTraps:[{scenario:"Using ceftolozane-tazobactam as a generic broad agent for ESBL or CRE when other preferred drugs are available",risk:"That burns a valuable Pseudomonas-focused reserve option without solving the actual resistance mechanism problem better.",saferApproach:"Save it for resistant Pseudomonas or other explicitly supported phenotypes where it offers a clear advantage.",sourceIds:["idsa-2024-amr"]},{scenario:"Continuing the lower cUTI-style regimen into pneumonia or severe bacteremia",risk:"The wrong dose can turn a microbiologically reasonable choice into an exposure failure.",saferApproach:"Use the 3 g q8h prolonged-infusion regimen when lung infection or high-inoculum disease is the reason it was selected.",sourceIds:["aspect-np","aspect-cuti-ciai"]}],administrationConstraints:[{title:"Pneumonia workflows should default to 3 g q8h over 3 hours",detail:"The lung dose and prolonged infusion are part of the intended resistant-Pseudomonas strategy, not optional escalations to add later.",action:"Hard-wire the pneumonia build into order sets for HAP/VAP and severe DTR Pseudomonas pathways.",sourceIds:["aspect-np","idsa-2024-amr"]},{title:"Elastomeric and post-acute delivery need local stability confirmation",detail:"Reserve-agent q8h infusion plans can fail after discharge if the receiving program cannot match the intended infusion model.",action:"Confirm the exact post-acute preparation workflow before promising OPAT or SNF continuation.",sourceIds:["idsa-2024-amr","aspect-cuti-ciai"]}],siteSpecificAvoidances:[{site:"Pneumonia treated with the lower cUTI/cIAI dosing strategy",reason:"The lower regimen can underdeliver exposure for lung infection and severe resistant Pseudomonas disease.",preferredApproach:"Use the 3 g q8h extended-infusion pneumonia regimen or choose another active agent.",sourceIds:["aspect-np","idsa-2024-amr"]}],penetration:[{site:"Lung / epithelial lining fluid",detail:"Adequate pulmonary penetration at the pneumonia dose and infusion strategy is one reason it is useful for resistant Pseudomonas pneumonia."},{site:"Urine",detail:"High urinary exposure supports use in cUTI caused by susceptible MDR gram-negative pathogens."},{site:"CSF",detail:"CNS experience is limited enough that it should not be assumed to cover meningitis simply because the isolate is susceptible."}]},{id:"imipenem-cilastatin-relebactam",name:"Imipenem-Cilastatin-Relebactam",brandNames:"Recarbrio",drugClass:"Carbapenem / beta-lactamase inhibitor combination",mechanismOfAction:"Imipenem (carbapenem) binds multiple PBPs causing cell wall inhibition and lysis. Cilastatin inhibits renal dehydropeptidase I (prevents imipenem hydrolysis in proximal tubules). Relebactam (diazabicyclooctane BLI) inhibits class A (KPC, ESBL) and class C (AmpC) beta-lactamases, restoring imipenem activity against resistant strains. Does NOT inhibit class B (metallo-BLI) or most class D (OXA-48+).",spectrum:"Enterobacteriaceae (including KPC-CRE), Pseudomonas aeruginosa (including DTR strains), Acinetobacter (variable). Gram-positive: MSSA, E. faecalis, Streptococcus. Anaerobes: Bacteroides, Peptostreptococcus. GAPS: MRSA, VRE, NDM/OXA-48-CRE (relebactam does not inhibit these), Stenotrophomonas.",dosing:{standard:"1.25g (500mg/500mg/250mg) IV q6h, infused over 30 minutes",renal_adjusted:"See table — dose adjusted for CrCl <90 mL/min"},renalAdjustment:"CrCl 60–89: 1g q6h. CrCl 30–59: 0.75g q6h. CrCl 15–29: 0.5g q6h. CrCl <15/HD: 0.5g q12h (dose after HD on HD days). Monitoring required.",hepaticAdjustment:"No hepatic dose adjustment. Primarily renally eliminated.",adverseEffects:{common:"Nausea, diarrhea, vomiting, elevated transaminases, phlebitis",serious:"Seizures (imipenem — lower seizure threshold than other carbapenems, particularly in patients with CNS disease or renal impairment with inadequate dose reduction), C. difficile colitis",rare:"Encephalopathy, hypotension",fdaBoxedWarnings:"Serious CNS adverse reactions including seizures — particularly in patients with CNS disorders and those with renal dysfunction receiving doses not adjusted for renal function."},drugInteractions:["Valproic acid — MAJOR: imipenem reduces valproic acid levels by 60-70% within 2 days. Risk of seizure due to sub-therapeutic valproate. Avoid combination; if necessary, consult neurology and monitor levels closely.","Ganciclovir — additive seizure risk when used concomitantly","Cyclosporine — additive CNS toxicity (tremors, seizures)"],monitoring:"Renal function (complex dosing). Seizure precautions. Valproic acid levels if co-prescribed. CBC, LFTs for prolonged therapy.",pregnancyLactation:"Category C. Animal studies showed some fetal harm. Limited human data. Use only for serious infections where benefits outweigh risks.",pkpdDriver:{driver:"Time-dependent (T>MIC)",target:"fT>MIC ≥40% (static), ≥80% (bactericidal) — free drug time above MIC",extendedInfusion:"Extended infusion over 3h improves target attainment — 0.5g component infused over 3h"},rapidDiagnostics:[{trigger:"KPC-producing Enterobacterales is confirmed and the isolate is susceptible",action:"Imipenem-cilastatin-relebactam is a reasonable definitive option, especially if ceftazidime-avibactam or meropenem-vaborbactam are unavailable or recently used.",rationale:"Relebactam restores imipenem activity for KPC and AmpC-driven resistance but not for MBL or OXA-48."},{trigger:"DTR Pseudomonas is confirmed without MBL",action:"Use imipenem-cilastatin-relebactam as a targeted reserve anti-pseudomonal option when susceptibility and seizure risk permit.",rationale:"Its role is strongest in imipenem-nonsusceptible Pseudomonas and selected KPC isolates."}],breakpointNotes:[{marker:"Mechanism dependence",interpretation:"A favorable result only makes sense if the resistance driver is KPC or AmpC rather than OXA-48 or an MBL.",action:"Keep carbapenemase testing connected to every susceptibility interpretation."},{marker:"Exposure strategy",interpretation:"The product is labeled as a 30-minute infusion, but extended infusion can improve target attainment in difficult isolates.",action:"If the MIC is borderline and the patient is critically ill, discuss the infusion strategy with stewardship or ID."}],intrinsicResistance:[{organism:"MBL-producing Enterobacterales or Pseudomonas",resistance:"Relebactam does not inhibit NDM, VIM, or IMP.",implication:"Do not expect rescue activity when an MBL is present."},{organism:"OXA-48-like CRE and Stenotrophomonas",resistance:"Activity is unreliable or absent because relebactam does not fix those core mechanisms.",implication:"Choose a more mechanism-specific agent instead."}],coverageMatrix:[{label:"KPC-CRE",status:"active",detail:"A viable definitive option when susceptible, though often ranked behind meropenem-vaborbactam or ceftazidime-avibactam."},{label:"DTR Pseudomonas without MBL",status:"preferred",detail:"An important reserve anti-pseudomonal option when local susceptibility supports it."},{label:"OXA-48-like or MBL CRE",status:"avoid",detail:"Do not rely on relebactam to rescue these mechanisms."},{label:"Stenotrophomonas",status:"inactive",detail:"No dependable role."}],opatEligibility:{eligible:"conditional",administration:"OPAT is possible but q6h dosing is burdensome and usually less attractive than other definitive options.",monitoring:"Weekly renal function and CBC are minimum expectations, with closer review for any neurologic symptoms.",considerations:["Consider only when the susceptibility pattern truly favors it and the infusion program can handle q6h dosing.","Poor OPAT choice if seizure risk or adherence concerns are present."]},pharmacistPearls:["CRITICAL: Imipenem DRAMATICALLY reduces valproic acid levels (>60% reduction within 2 days). This is one of the most dangerous drug-drug interactions in infectious disease. If a patient is on valproic acid, either avoid imipenem/IC-R or transition valproate to a different antiepileptic with neurology guidance.","Imipenem has the lowest seizure threshold of all carbapenems — particularly dangerous in patients with prior seizures, CNS lesions, or renal impairment (if dose not properly adjusted).","IC-Relebactam is preferred over colistin for carbapenem-resistant Pseudomonas and KPC-CRE based on RESTORE-IMI trial data — significantly better safety profile.","Relebactam does NOT inhibit metallo-beta-lactamases (NDM, VIM) or OXA-48. If these are present, IC-R will fail. Carbapenemase testing is mandatory before use.","The RESTORE-IMI 2 trial showed IC-R was non-inferior to piperacillin-tazobactam for HAP/VAP, with activity against pip-tazo resistant Pseudomonas."],dosingByIndication:[{label:"DTR Pseudomonas or selected KPC infection",regimen:"1.25 g IV q6h",notes:"Use as a mechanism-directed reserve option rather than a default carbapenem escalation."}],renalReplacement:[{modality:"HD",guidance:"Use the renally adjusted regimen after hemodialysis because the q6h schedule is already easy to underdeliver."},{modality:"CRRT",guidance:"CRRT often still requires aggressive q6h coverage; seizure risk and effluent rate both matter when adjusting."}],specialPopulations:[{population:"Seizure risk or advanced CNS disease",guidance:"Imipenem still carries more seizure concern than meropenem, so choose carefully when the brain is already vulnerable."},{population:"Unknown carbapenemase mechanism",guidance:"Do not assume activity for all resistant gram-negatives; the phenotype still has to fit relebactam's mechanism."}],therapeuticDrugMonitoring:{target:"No routine serum target; the real target is correct mechanism coverage with dependable q6h exposure.",sampling:"Drug levels are not standard. Review seizure history, renal function, and susceptibility mechanism closely.",adjustment:"If neurotoxicity or mechanism mismatch is emerging, pivot early rather than treating it as a generic carbapenem failure."},administration:{infusion:"Administer on the scheduled q6h interval with disciplined timing because missed doses rapidly erode coverage.",compatibility:"Frequent dosing increases line-scheduling conflicts, so compatibility planning matters in ICU patients.",note:"Operational burden is one reason it is usually a targeted reserve choice rather than a discharge favorite."},ivToPoSwitch:{poBioavailability:"No oral formulation exists.",switchCriteria:"Most patients remain on IV therapy until cure or change to another active class because true oral exits are uncommon.",note:"If a reliable oral option appears, that usually means the resistant phenotype was narrower than first feared."},interactionActions:[{interactingAgent:"Valproic acid",effect:"Imipenem-class carbapenems can markedly lower valproate exposure and trigger seizures.",management:"Use an alternative antiepileptic for the full carbapenem course.",severity:"major"},{interactingAgent:"Ganciclovir or other seizure-threshold-lowering drugs",effect:"Can amplify CNS toxicity in already vulnerable patients.",management:"Review neurotoxicity risk before committing to prolonged therapy.",severity:"monitor"}],stewardshipUseCases:[{scenario:"Targeted DTR Pseudomonas therapy",role:"A reserve anti-pseudomonal option when susceptibility and mechanism support it.",notes:"Do not use it just because cefepime feels emotionally too small."},{scenario:"Selected KPC infection when other preferred agents are unavailable or recently used",role:"A reasonable mechanism-directed backup rather than a universal first choice.",notes:"Keep the reason for choosing it explicit in the stewardship note."}],monitoringActions:[{trigger:"New encephalopathy, seizure activity, or renal decline while on q6h therapy",action:"Reassess dosing and drug choice immediately instead of treating the neurotoxicity signal as nonspecific ICU delirium.",rationale:"Imipenem exposure and CNS vulnerability can become the dominant execution risk quickly.",sourceIds:["idsa-2024-amr","restore-imi-1"]},{trigger:"Updated microbiology suggests MBL or another relebactam-mismatched phenotype",action:"Stop treating the regimen as definitive and switch to a mechanism-appropriate option.",sourceIds:["idsa-2024-amr","restore-imi-1"]}],misuseTraps:[{scenario:"Escalating to imipenem-cilastatin-relebactam as a generic carbapenem upgrade without documenting the mechanism",risk:"This turns a targeted reserve drug into broad emotional escalation and can miss the actual resistant phenotype.",saferApproach:"Use it only when the organism, site, and susceptibility pattern fit relebactam's role.",sourceIds:["idsa-2024-amr","restore-imi-1"]},{scenario:"Keeping valproate or other seizure-threshold stressors in place without a neurotoxicity plan",risk:"Operationally convenient continuation can precipitate breakthrough seizures or force abrupt therapy changes.",saferApproach:"Coordinate antiepileptic substitution and neurologic monitoring before prolonged therapy.",sourceIds:["idsa-2024-amr","restore-imi-1"]}],administrationConstraints:[{title:"Q6h timing discipline is part of the drug's value",detail:"Missed or delayed doses erode exposure quickly, especially in ICU patients with changing clearance.",action:"Treat schedule drift as a pharmacy-nursing workflow issue to fix, not a minor delay to tolerate.",sourceIds:["idsa-2024-amr","restore-imi-1"]},{title:"Neurotoxicity handoff belongs in transfer and discharge planning",detail:"This regimen is operationally fragile when neurologic risk, renal instability, and q6h delivery all travel with the patient.",action:"Document seizure history, renal plan, and why a q6h reserve regimen remains necessary before transfer.",sourceIds:["idsa-2024-amr"]}],siteSpecificAvoidances:[{site:"MBL-producing infection regardless of anatomic source",reason:"Relebactam does not overcome MBL-mediated resistance, so apparent carbapenem escalation does not fix the biology.",preferredApproach:"Switch to an MBL-active regimen instead of intensifying imipenem-cilastatin-relebactam.",sourceIds:["idsa-2024-amr"]}],penetration:[{site:"Lung / epithelial lining fluid",detail:"Pulmonary exposure is sufficient for susceptible resistant gram-negative pneumonia when full-dose q6h therapy is used."},{site:"Urine",detail:"Renal elimination produces strong urinary exposure, making it useful in resistant cUTI and urinary-source bacteremia."},{site:"CSF",detail:"CNS use is not a strength because seizure liability and limited data make other carbapenems easier choices for meningitis."}]},{id:"colistin",name:"Colistin (Polymyxin E)",brandNames:"Coly-Mycin M (colistimethate sodium — prodrug); Colistin (active form)",drugClass:"Polymyxin antibiotic",mechanismOfAction:"Colistimethate sodium (CMS) is the inactive prodrug — converts to colistin (active) in vivo and in solution. Colistin disrupts the outer membrane of gram-negative bacteria by competitively displacing Ca²⁺ and Mg²⁺ from lipopolysaccharide (LPS) phosphate groups, increasing membrane permeability and causing cell lysis. Concentration-dependent bactericidal activity. Does NOT enter gram-positive cells (no outer membrane).",spectrum:"Gram-negative only: Acinetobacter baumannii, Pseudomonas aeruginosa, Klebsiella pneumoniae. The 'drug of last resort' for pan-drug-resistant organisms. GAPS: Proteus, Providencia, Serratia, Morganella (intrinsically resistant — lack LPS modifications), gram-positive, anaerobes, fungi.",dosing:{loading:"Loading dose: 9 MU CMS IV over 30 min (to rapidly achieve target concentrations)",maintenance:"Maintenance: 4.5 MU CMS IV q12h (normal renal function). DOSE IN MIU OF CMS not mg of colistin base — units are confusing, always double-check.",inhaled:"Inhaled: 1–2 MIU CMS via nebulizer q12h (for pulmonary MDR infections as adjunct to IV)",note:"Dosing is complex and confusing — colistin base activity (CBA) vs colistimethate sodium (CMS) mg vs MIU. Consult clinical pharmacy for all patients."},renalAdjustment:"CRITICAL and complex. CMS is primarily renally eliminated; colistin (active) accumulates in renal insufficiency causing toxicity. CrCl 50–79: load 9 MU, then 5.5 MU/day in 2 doses. CrCl 30–49: 4.5 MU/day. CrCl 10–29: 3.5 MU/day. HD: dose post-HD. ID/PK consultation mandatory — incorrect dosing causes nephrotoxicity without efficacy.",hepaticAdjustment:"No specific hepatic adjustment — primarily renally eliminated.",adverseEffects:{common:"Nephrotoxicity (30–50% of patients; ATN/AKI — usually reversible), neurotoxicity (paresthesias, dizziness, slurred speech, ataxia — in up to 27%)",serious:"Severe acute kidney injury (potentially requiring dialysis), respiratory failure/neuromuscular blockade (rare), respiratory failure with nebulized form (bronchospasm)",rare:"Apnea (neuromuscular blockade at high serum levels), severe respiratory failure with inhaled route",fdaBoxedWarnings:"Nephrotoxicity and neurotoxicity. Reserve for infections due to susceptible organisms when safer alternatives are not available. Renal function should be monitored carefully; dosing adjustments required."},drugInteractions:["Aminoglycosides — additive nephrotoxicity; avoid if possible","Vancomycin — additive nephrotoxicity; use with extreme caution","Neuromuscular blocking agents — potentiation of NMB; may cause respiratory arrest","Amphotericin B — additive nephrotoxicity","Loop diuretics — additive nephrotoxicity","Non-depolarizing muscle relaxants — enhanced neuromuscular blockade"],monitoring:"Serum creatinine DAILY. Urine output hourly in critical patients. Serum colistin levels if available (PK-guided dosing). Neurological assessment (slurred speech, paresthesias, confusion — often early toxicity warning). Avoid concomitant nephrotoxins if at all possible. Electrolytes daily (hypokalemia, hypomagnesemia common).",pregnancyLactation:"Category C. Avoid unless benefit clearly outweighs risk — fetal risk extrapolated from nephrotoxicity profile. Limited human data. Not recommended in breastfeeding.",pkpdDriver:{driver:"AUC/MIC-dependent",target:"AUC/MIC ≥50 (free drug); always use in combination — never monotherapy except in extreme circumstances",extendedInfusion:"Loading dose mandatory to achieve target Css rapidly; maintenance as described"},opatEligibility:{eligible:"no",administration:"The toxicity burden and dosing complexity make routine OPAT a poor fit.",monitoring:"Daily or near-daily renal and neurologic review is usually needed early in therapy.",considerations:["Use inpatient or highly supervised subacute settings rather than standard home OPAT.","Reserve for situations where better tolerated active agents are unavailable."]},pharmacistPearls:["DOSING CONFUSION IS A PATIENT SAFETY ISSUE: Colistin doses are expressed in different units by different manufacturers and references — colistimethate sodium (CMS) MIU, mg of CMS, or colistin base activity (CBA). ALWAYS verify units with the specific product you have. This has caused fatal overdoses.","A loading dose is mandatory — CMS conversion to active colistin is slow (t½ CMS → colistin ~7h). Without loading, therapeutic levels are not achieved for 12–24h in a critically ill patient.","Nephrotoxicity is 30–50% in clinical practice. Hydration, avoidance of other nephrotoxins, and dose optimization are critical mitigation strategies.","NEVER use colistin as monotherapy if any other agent shows activity — combination with carbapenem, rifampin, or fosfomycin improves outcomes and reduces resistance emergence.","Colistin resistance during therapy is a real risk — follow-up cultures are essential.","The emergence of novel agents (IC-relebactam, ceftazidime-avibactam, ceftolozane-tazobactam) has significantly reduced the indications for colistin. If any of these agents cover the organism, they are preferred."],dosingByIndication:[{label:"Salvage therapy for DTR gram-negative infection",regimen:"Load with 9 MIU colistimethate, then maintenance per renal function and product-specific units",notes:"Consult a PK-savvy pharmacist or institutional nomogram because unit confusion is a patient-safety issue."}],renalReplacement:[{modality:"HD",guidance:"Use level- or protocol-driven post-hemodialysis dosing because both the prodrug and active form create dosing confusion in dialysis patients."},{modality:"CRRT",guidance:"CRRT dosing is highly individualized and should follow an experienced protocol because both underexposure and toxicity are easy to create."}],specialPopulations:[{population:"Baseline CKD or concurrent nephrotoxins",guidance:"If any safer active agent exists, use it instead because kidney injury risk is often the reason colistin cannot be completed."},{population:"Neuromuscular disease",guidance:"Colistin can worsen weakness and respiratory compromise, so use only when the microbiology gain is worth that neurologic risk."}],therapeuticDrugMonitoring:{target:"No widely available bedside target, but PK-guided dosing is ideal when the service offers it because therapeutic and toxic exposures overlap.",sampling:"If levels are available, use them. Otherwise monitor renal function, urine output, neurologic symptoms, and whether the regimen still needs colistin at all.",adjustment:"Do not respond to toxicity by casually stretching the interval without re-evaluating whether a safer active option has become available."},administration:{infusion:"A loading dose is mandatory; maintenance infusions then follow the institution's unit-specific protocol.",compatibility:"Verify units and product formulation every time because CMS and colistin base activity are easy to confuse.",note:"This is a drug where operational precision is as important as microbiology."},ivToPoSwitch:{poBioavailability:"No oral systemic formulation exists.",switchCriteria:"True oral step-down is not expected; the transition question is usually whether colistin can be stopped for a safer IV or oral alternative.",note:"If the patient improves and susceptibilities open another door, take it."},interactionActions:[{interactingAgent:"Vancomycin, amphotericin B, aminoglycosides, or other nephrotoxins",effect:"Additive kidney injury is common and can force premature discontinuation.",management:"Strip out avoidable nephrotoxins and shorten overlap aggressively.",severity:"major"},{interactingAgent:"Neuromuscular blocking agents",effect:"Can worsen neuromuscular weakness and respiratory failure risk.",management:"Use extreme caution in ventilated or perioperative patients and monitor closely.",severity:"major"}],stewardshipUseCases:[{scenario:"Last-line salvage for highly resistant gram-negative infection",role:"A fallback only when newer beta-lactam options are inactive, unavailable, or inappropriate.",notes:"Always document why safer reserve agents cannot be used."},{scenario:"Prompt de-escalation once a safer active option appears",role:"The stewardship goal with colistin is usually to get off colistin as soon as microbiology permits.",notes:"Do not keep it just because the patient is already tolerating it today."}],monitoringActions:[{trigger:"Serum creatinine rises, urine output falls, or dialysis needs change after the loading dose",action:"Recalculate dosing and reassess whether colistin is still necessary instead of simply stretching intervals and hoping toxicity stabilizes.",rationale:"Nephrotoxicity is the dominant operational failure mode and can evolve before the microbiology plan changes.",sourceIds:["idsa-2024-amr","credible-cr"]},{trigger:"New paresthesias, weakness, apnea risk, or escalating neuromuscular blocker exposure",action:"Treat neurotoxicity as a reason to stop or replace colistin, not just a side effect to monitor passively.",sourceIds:["idsa-2024-amr"]}],misuseTraps:[{scenario:"Starting or continuing colistin when a newer beta-lactam or sulbactam-based option is active",risk:"The toxicity burden is rarely justified once a safer active alternative exists.",saferApproach:"Use colistin only when better tolerated mechanism-appropriate options are truly unavailable or inactive.",sourceIds:["idsa-2024-amr","attack","credible-cr"]},{scenario:"Skipping the loading dose or mixing CMS and colistin-base units loosely across handoffs",risk:"Unit confusion and underloading can produce both early failure and preventable toxicity.",saferApproach:"Use a protocolized loading strategy with explicit unit language at every order and transfer step.",sourceIds:["idsa-2024-amr"]}],administrationConstraints:[{title:"Unit language must be standardized every time",detail:"Confusion between colistimethate sodium and colistin-base activity remains a serious medication-safety risk.",action:"Spell out units, formulation, and maintenance strategy in the order and transfer documentation.",sourceIds:["idsa-2024-amr"]},{title:"Colistin needs a predeclared exit strategy",detail:"Because toxicity accumulates quickly, teams should know what result or clinical milestone would let them stop it.",action:"Document the stop trigger at initiation and revisit it with each culture update.",sourceIds:["idsa-2024-amr","credible-cr"]}],siteSpecificAvoidances:[{site:"Pneumonia, bloodstream infection, or other deep-seated disease when a safer active reserve agent exists",reason:"Colistin's narrow therapeutic window and inferior tolerability make it a poor definitive anchor once another active option is available.",preferredApproach:"Move to the mechanism-directed beta-lactam or sulbactam-based regimen as soon as susceptibilities allow.",sourceIds:["idsa-2024-amr","attack","credible-cr"]}],penetration:[{site:"Urine",detail:"When given as colistimethate, renal excretion can produce clinically useful urinary concentrations for highly resistant lower-tract infection."},{site:"Lung",detail:"IV colistin alone gives variable lung exposure, which is why inhaled adjunct therapy is often considered for severe MDR pneumonia."},{site:"CSF",detail:"Systemic CSF penetration is poor, so intrathecal or intraventricular therapy may be required when no better CNS-active option exists."}]},{id:"tedizolid",name:"Tedizolid",brandNames:"Sivextro",drugClass:"Oxazolidinone antibiotic (2nd generation)",mechanismOfAction:"Binds to the 50S ribosomal subunit (23S rRNA, domain V) — same mechanism as linezolid but with enhanced binding affinity (lower MIC vs. most organisms). Inhibits translation initiation complex formation (blocks 70S ribosome assembly). Bacteriostatic against most organisms; bactericidal against some staphylococci.",spectrum:"Gram-positive only: MRSA (excellent), MSSA, VRE (E. faecalis and E. faecium), streptococci (including viridans), Streptococcus pneumoniae (including DRSP), Listeria. GAPS: All gram-negatives, anaerobic gram-negatives. Activity against some linezolid-resistant strains (different binding interaction). NO activity against fungi.",dosing:{absssi:"200mg IV or PO once daily × 6 days",hap_consideration:"200mg IV q24h (not FDA-approved for HAP, but studied; controversial data)"},renalAdjustment:"No dose adjustment required for any degree of renal impairment, including dialysis. This is a significant advantage over linezolid (linezolid metabolites accumulate in renal impairment).",hepaticAdjustment:"No dose adjustment required for hepatic impairment. Tedizolid undergoes hepatic glucuronidation (UGT pathways) and is eliminated via biliary/fecal route.",adverseEffects:{common:"Nausea, headache, diarrhea, vomiting (GI effects generally less than linezolid)",serious:"Myelosuppression (thrombocytopenia, anemia, neutropenia — LESS common than linezolid in trials; monitor CBC if extended use)",rare:"Serotonin syndrome (5-HT mechanism similar to linezolid but slightly lower theoretical risk), optic neuropathy with prolonged use, peripheral neuropathy"},drugInteractions:["MAO inhibitors — CONTRAINDICATED: serotonin syndrome and hypertensive crisis risk (same as linezolid)","Serotonergic drugs (SSRIs, SNRIs, TCA, triptans, meperidine, dextromethorphan) — risk of serotonin syndrome; assess risk:benefit","Adrenergic drugs (sympathomimetics, vasopressors) — potential enhanced pressor response (monoamine oxidase mechanism)","Tyramine-rich foods — unlike MAOIs, tedizolid interaction appears less significant than linezolid (selective vs. non-selective MAO inhibition), but still counsel patients","Rifampin — reduces tedizolid exposure (OATP1B inhibition); avoid combination or monitor"],monitoring:"CBC at baseline and weekly for courses >6 days (especially platelets — serotonin pathway in platelets). Monitor for signs of serotonin syndrome. Visual symptoms (optic neuropathy) for prolonged courses.",pregnancyLactation:"Category C. Animal embryo-fetal toxicity data. No adequate human data. Avoid unless benefits outweigh risks.",ivToPoSwitch:{poBioavailability:"High oral bioavailability with near-IV exposure.",switchCriteria:"Switch to PO as soon as oral intake is reliable because the same daily dose is used.",note:"One of the cleanest day-1 or day-2 IV-to-PO conversions for gram-positive skin infection."},opatEligibility:{eligible:"conditional",administration:"IV OPAT is possible, but oral once-daily therapy is usually the better outpatient route.",monitoring:"CBC and serotonergic symptom review still matter whether the route is IV or PO.",considerations:["Prefer oral completion over home IV infusion whenever feasible.","Use mostly in short-course SSTI pathways rather than prolonged invasive infection plans."]},pharmacistPearls:["Tedizolid 200mg QD × 6 days vs. linezolid 600mg BID × 10 days — non-inferior for MRSA ABSSSI per ATTAIN trials. Shorter course, once daily = significant patient advantage.","The key pharmacist advantage of tedizolid over linezolid: NO dose adjustment in renal failure, and generally better tolerated (less myelosuppression, less GI effects). Reserve linezolid for when cost is the primary driver.","Both tedizolid and linezolid are monoamine oxidase inhibitors. Serotonin syndrome with concomitant serotonergic agents (SSRIs, SNRIs) is a real risk — always reconcile medications.","Tedizolid is bacteriostatic for most organisms. Do NOT use for bacteremia, endocarditis, or osteomyelitis as primary therapy — these require bactericidal agents.","Oral bioavailability >90% — this is equivalent to IV. IV-to-PO switch at day 1–2 of therapy is appropriate and cost-effective.","Cost: tedizolid is significantly more expensive than linezolid. In formulary-restricted settings, document MRSA + linezolid intolerance or failure to justify tedizolid."],dosingByIndication:[{label:"ABSSSI",regimen:"200 mg IV/PO daily for 6 days",notes:"Best used when a short-course once-daily gram-positive oral option is the real goal."}],renalReplacement:[{modality:"HD",guidance:"No dose adjustment is usually needed, which is part of tedizolid's operational appeal."},{modality:"CRRT",guidance:"Standard daily dosing usually remains appropriate because renal clearance is not the main driver."}],specialPopulations:[{population:"Patients with renal dysfunction or linezolid intolerance risk",guidance:"Tedizolid can be attractive when you want oxazolidinone activity with less concern about renal metabolite accumulation."},{population:"Bacteremia or deep-seated invasive infection",guidance:"Do not overextend tedizolid into syndromes where the evidence base is much thinner than for skin infection."}],therapeuticDrugMonitoring:{target:"No routine serum target; success depends on syndrome fit and toxicity surveillance rather than drug levels.",sampling:"No standard drug levels are used. Follow CBC and serotonergic toxicity context when courses extend.",adjustment:"If deeper infection is declared later, switch to a better-validated agent rather than forcing tedizolid to cover more than it should."},administration:{infusion:"IV administration is once daily; switch to PO quickly when possible.",oralAbsorption:"High oral bioavailability makes IV-to-PO conversion straightforward.",note:"The operational advantage is once-daily oral completion rather than prolonged IV therapy."},interactionActions:[{interactingAgent:"Serotonergic drugs",effect:"Can increase serotonin-toxicity risk, even if the signal may be somewhat lower than with linezolid.",management:"Reconcile serotonergic medications before starting therapy and monitor closely if overlap is unavoidable.",severity:"major"},{interactingAgent:"Rifampin",effect:"Can lower tedizolid exposure.",management:"Avoid the combination or use only with a clear rationale and close follow-up.",severity:"monitor"}],stewardshipUseCases:[{scenario:"Short-course gram-positive skin infection",role:"A once-daily oral-capable option when linezolid-like activity is useful but a shorter course is appealing.",notes:"Its best stewardship role is simplifying outpatient management, not covering deep bacteremia."},{scenario:"Avoiding unnecessary prolonged IV gram-positive therapy",role:"High oral bioavailability can shorten line days quickly when the syndrome fits.",notes:"Do not confuse convenience with evidence for invasive disease."}],penetration:[{site:"Skin / soft tissue",detail:"Excellent soft-tissue exposure supports once-daily treatment of gram-positive skin infection."},{site:"Lung",detail:"Pulmonary penetration is good enough to make tedizolid biologically interesting for pneumonia, even though routine HAP use remains limited."},{site:"Bone / joint",detail:"Bone penetration is reasonable, but the clinical experience is still thinner than with linezolid for long osteoarticular courses."}]},{id:"posaconazole",name:"Posaconazole",brandNames:"Noxafil (oral suspension, tablets, IV), Posanol",drugClass:"Triazole antifungal",mechanismOfAction:"Inhibits lanosterol 14α-demethylase (CYP51) in the ergosterol biosynthesis pathway. Blocks conversion of lanosterol to ergosterol — depletes fungal cell membrane ergosterol, disrupting membrane integrity and function. Extended spectrum compared to fluconazole/voriconazole due to structural modifications allowing binding to resistant CYP51 variants.",spectrum:"Extended-spectrum triazole: Aspergillus (including some voriconazole-resistant strains), Candida (most species including non-albicans), Mucorales (Mucor, Rhizopus — unique among azoles), Fusarium (variable), Histoplasma, Coccidioides, Blastomyces, Cryptococcus. KEY advantage over voriconazole: Mucorales coverage. Limited activity against Candida krusei.",dosing:{prophylaxis_tablet:"300mg PO BID day 1 (load), then 300mg PO QD (DR tablets — preferred formulation)",prophylaxis_suspension:"200mg PO TID (oral suspension — requires high-fat meal or acidic drink for absorption, inconsistent)",treatment_invasive:"300mg IV q12h day 1, then 300mg IV QD (IV preferred for invasive disease — reliable levels)",prophylaxis_iv:"300mg IV QD for patients unable to take oral"},renalAdjustment:"IV formulation contains sulfobutylether-beta-cyclodextrin (SBECD) vehicle — avoid IV if CrCl <50 mL/min due to SBECD accumulation (nephrotoxic). Oral formulations safe in all degrees of renal impairment.",hepaticAdjustment:"No dose adjustment in mild-moderate hepatic disease. Use with caution in severe hepatic impairment; monitor LFTs closely.",adverseEffects:{common:"Nausea, vomiting, diarrhea, abdominal pain, headache, elevated LFTs",serious:"Hepatotoxicity (monitor LFTs), QT prolongation (additive with other QT-prolonging drugs), adrenal insufficiency with prolonged use (CYP3A4 inhibition affects cortisol metabolism)",rare:"Severe hepatic toxicity, visual disturbances (less common than voriconazole), photosensitivity"},drugInteractions:["Posaconazole is a POTENT CYP3A4 inhibitor and P-glycoprotein inhibitor — MAJOR interactions","Calcineurin inhibitors (tacrolimus, cyclosporine, sirolimus) — dramatically increase levels; reduce dose by 50-75% and monitor levels frequently","Statins metabolized by CYP3A4 (simvastatin, lovastatin, atorvastatin) — markedly increased statin levels → rhabdomyolysis risk; hold or switch to pravastatin","Rifampin/rifabutin — dramatically reduce posaconazole levels; avoid combination","Midazolam — levels increased 5-fold; respiratory depression risk","QT-prolonging agents (quinolones, macrolides, antiarrhythmics) — additive QT prolongation","Phenytoin, carbamazepine, barbiturates — reduce posaconazole levels significantly; monitor","Methadone, fentanyl — increased opioid levels; monitor for toxicity"],monitoring:"LFTs at baseline and during therapy. QT interval (ECG). Serum posaconazole trough level (target ≥0.5-1 mg/L for prophylaxis; ≥1-2 mg/L for treatment). Electrolytes (especially K, Mg — correct hypokalemia/hypomagnesemia to reduce QT risk). Monitor all co-administered drugs for interactions.",pregnancyLactation:"Category C. Teratogenic in animal studies. Avoid in pregnancy unless life-threatening fungal infection with no alternatives. Contraception required during therapy.",ivToPoSwitch:{poBioavailability:"Delayed-release tablets have dependable oral exposure; suspension is less reliable and more food dependent.",switchCriteria:"Switch to delayed-release tablets when oral intake is reliable and absorption barriers are manageable.",note:"Avoid converting to suspension unless there is a compelling reason and a level-monitoring plan."},opatEligibility:{eligible:"yes",administration:"Once-daily oral delayed-release tablets make outpatient prophylaxis or step-down practical without IV access.",monitoring:"Trough levels, LFTs, QT context, and interacting-drug levels all require structured follow-up.",considerations:["Excellent outpatient prophylaxis drug when the interaction burden is actively managed.","Do not discharge on posaconazole without reviewing immunosuppressants and formulation."]},pharmacistPearls:["THE critical distinction: Posaconazole is the ONLY triazole with reliable Mucorales (mucormycosis) coverage. If the question is 'broad antifungal prophylaxis in immunocompromised patient including Mucor coverage' — posaconazole, isavuconazole, or L-AmB are the options.","Oral suspension is the old formulation — avoid it when possible. Absorption is highly variable, food-dependent, and unreliable in mucositis or GI dysfunction (exactly when prophylaxis is needed most). The DR tablet (300mg QD) is the current standard.","Drug interactions are extensive and severe. ALWAYS conduct a full medication reconciliation. Tacrolimus/cyclosporine dose reduction of 50-75% is typically required — failure to do so causes calcineurin inhibitor toxicity.","Posaconazole prophylaxis is standard of care (IDSA 2016, ESCMID 2022) in AML patients receiving remission-induction chemotherapy — reduces IA incidence from ~12% to ~5% and improves survival.","Therapeutic drug monitoring (TDM) is recommended for treatment (target trough ≥1-2 mg/L) and optional for prophylaxis (target ≥0.5-1 mg/L). Drug levels help ensure adequate exposure and avoid toxicity.","Correct hypokalemia and hypomagnesemia before starting posaconazole — electrolyte abnormalities potentiate QT prolongation."],dosingByIndication:[{label:"Mold prophylaxis",regimen:"300 mg PO BID day 1, then 300 mg PO daily using delayed-release tablets",notes:"The tablet formulation is strongly preferred over suspension for reliable outpatient prophylaxis."},{label:"Treatment of invasive mold infection",regimen:"300 mg IV or PO q12h day 1, then 300 mg daily",notes:"Use as a treatment or salvage azole when drug levels and interaction management can be supported."}],renalReplacement:[{modality:"HD",guidance:"Oral formulations do not require dose adjustment; avoid IV formulation in significant renal dysfunction because of SBECD concerns when possible."},{modality:"CRRT",guidance:"Oral therapy is usually preferred if feasible; if IV is necessary, reassess renal and vehicle exposure frequently."}],specialPopulations:[{population:"Transplant recipients or patients on calcineurin inhibitors",guidance:"This is an interaction-heavy drug where immunosuppressant adjustment must be part of the plan before the first dose."},{population:"Mucositis, GI dysfunction, or unpredictable absorption",guidance:"Use delayed-release tablets or IV therapy rather than relying on the older suspension in patients with impaired absorption."}],therapeuticDrugMonitoring:{target:"Trough at least 0.5-1 mcg/mL for prophylaxis and often at least 1-1.5 mcg/mL for treatment depending on syndrome and local practice.",sampling:"Check troughs after steady state and with major formulation, interaction, or GI-status changes.",adjustment:"If the level is low, fix the formulation or interaction problem before just escalating the dose."},administration:{infusion:"IV loading and daily maintenance are available when oral absorption is unreliable.",oralAbsorption:"Delayed-release tablets provide far more dependable exposure than the suspension and are preferred for outpatient use.",note:"Formulation choice is a core clinical decision with posaconazole, not a dispensing detail."},interactionActions:[{interactingAgent:"Tacrolimus, cyclosporine, or sirolimus",effect:"Posaconazole can dramatically raise calcineurin- or mTOR-inhibitor exposure.",management:"Preemptively reduce doses and monitor drug levels closely when starting or stopping posaconazole.",severity:"major"},{interactingAgent:"CYP3A4-metabolized statins or QT-prolonging drugs",effect:"Can raise toxicity risk or amplify QT prolongation.",management:"Hold or switch interacting drugs when possible and review ECG and medication context carefully.",severity:"major"}],stewardshipUseCases:[{scenario:"Outpatient mold prophylaxis in high-risk hematology or transplant patients",role:"A high-value preventive antifungal when Mucorales coverage and once-daily oral dosing matter.",notes:"Its stewardship success depends on doing the interaction work well."},{scenario:"Avoiding amphotericin exposure when an active oral mold-active azole is appropriate",role:"Can provide a safer outpatient continuation path in selected patients once levels are therapeutic and site fit is acceptable.",notes:"Do not use it casually where CNS or absorption reliability is uncertain without TDM support."}],penetration:[{site:"Lung / deep tissue",detail:"Good lung and tissue penetration supports prophylaxis and treatment roles in invasive mold disease, especially when Mucorales coverage is needed."},{site:"CSF / brain",detail:"CNS exposure is variable and generally less predictable than voriconazole, so brain infection needs careful drug-level and outcome review."},{site:"Urine",detail:"Urinary concentrations are poor, so posaconazole is not the azole to reach for in fungal UTI."}]},{id:"liposomal-amphotericin-b",name:"Liposomal Amphotericin B (L-AmB)",brandNames:"AmBisome",drugClass:"Polyene antifungal — liposomal formulation",mechanismOfAction:"Binds ergosterol in fungal cell membranes with high affinity, forming transmembrane pores that cause electrolyte leakage and cell death. Liposomal encapsulation (unilamellar lipid vesicles) delivers drug directly to fungal cell membranes while dramatically reducing binding to mammalian cell cholesterol — this is the basis of the superior safety profile vs. conventional AmB deoxycholate. Concentration-dependent fungicidal activity.",spectrum:"Broadest antifungal spectrum available: ALL Candida species (including azole-resistant), ALL Aspergillus species, ALL Mucorales (Mucor, Rhizopus, Lichtheimia), Fusarium, Cryptococcus, Histoplasma, Coccidioides, Blastomyces, endemic fungi, Dimorphic fungi. Essentially no clinically relevant primary resistance. Drug of LAST RESORT and drug of FIRST RESORT when spectrum uncertainty is high.",dosing:{candidemia:"3-5 mg/kg IV QD",invasive_aspergillosis:"3-5 mg/kg IV QD (second-line after voriconazole/isavuconazole)",cryptococcal_meningitis:"3-4 mg/kg IV QD (induction, with flucytosine × 2 weeks)",mucormycosis:"5-10 mg/kg IV QD (high dose — Mucorales less susceptible than Candida/Aspergillus)",empiric_febrile_neutropenia:"3 mg/kg IV QD",cns_or_renal_disease:"6 mg/kg IV QD (higher doses for CNS/renal candidiasis)"},renalAdjustment:"No dose adjustment required — a KEY advantage over conventional AmB. L-AmB is safe in significant renal impairment (CrCl <10, hemodialysis). This is one of the most important clinical advantages of the liposomal formulation.",hepaticAdjustment:"No dose adjustment in hepatic impairment. Primarily eliminated via biliary route.",adverseEffects:{common:"Infusion-related reactions (fever, rigors, chills, nausea — much less than conventional AmB, occurs in ~10% vs. 70-80%). Premedicate with acetaminophen ± diphenhydramine. Hypokalemia, hypomagnesemia (tubular loss).",serious:"Nephrotoxicity (MUCH less than conventional AmB but still possible — incidence ~15-20% vs. 50-80% with deoxycholate). Hypokalemia can be severe and require significant supplementation.",rare:"Hepatotoxicity, back/chest pain during infusion (associated with lipid component), anaphylaxis (rare)",contraindications:"Known hypersensitivity to amphotericin B or the liposomal formulation components."},drugInteractions:["Aminoglycosides — additive nephrotoxicity; monitor renal function","Calcineurin inhibitors (cyclosporine, tacrolimus) — additive nephrotoxicity","Potassium-depleting diuretics (loop, thiazide) — additive hypokalemia","Antineoplastic agents (vincristine, cyclophosphamide) — additive toxicity (pulmonary/nephrotoxicity)","Corticosteroids — additive hypokalemia; electrolyte monitoring critical","Flucytosine — SYNERGISTIC combination for cryptococcal meningitis induction therapy; also additive toxicity","Digoxin — hypokalemia from AmB increases digoxin toxicity risk","Azole antifungals — reduced AmB activity (ergosterol depletion by azoles reduces AmB binding site) — avoid combination unless specific clinical indication"],monitoring:"Serum creatinine, BUN, electrolytes (K, Mg, Na, bicarbonate) DAILY for the first 2 weeks; then 2-3×/week. CBC weekly. LFTs. Input/output. Renal potassium wasting often requires aggressive supplementation (2-4g KCl/day not uncommon). Monitor for infusion reactions — particularly first dose.",pregnancyLactation:"Category B (L-AmB). Conventional AmB is the preferred antifungal for life-threatening fungal infections in pregnancy. L-AmB preferred over conventional for reduced toxicity. Use when indicated — systemic fungal infections in pregnancy are serious and treatment is required.",pkpdDriver:{driver:"AUC/MIC-dependent",target:"AUC/MIC ≥25-50 for Candida; higher targets for Aspergillus and Mucorales",extendedInfusion:"Infuse over 2h (standard) — reducing infusion time to 1h associated with more infusion reactions; 4h infusion may improve tolerability in sensitive patients"},opatEligibility:{eligible:"conditional",administration:"Outpatient infusion is possible in carefully selected stable patients, but the lab and electrolyte burden is much heavier than with most OPAT drugs.",monitoring:"At least twice-weekly renal and electrolyte review is often needed even after inpatient stabilization.",considerations:["Reasonable only when the patient is clinically stable and the outpatient program can handle frequent lab-driven supplementation.","Poor fit when ongoing AKI, recurrent rigors, or rapid electrolyte replacement is still occurring."]},pharmacistPearls:["L-AmB ≠ Conventional AmB: Do NOT interchange without clinical justification. L-AmB (AmBisome) is the preferred formulation due to dramatically improved safety. Conventional amphotericin B deoxycholate (Fungizone) has 50-80% nephrotoxicity and 70-80% infusion reaction rates — it should not be used when L-AmB is available.","Premedicate: Acetaminophen 650mg + diphenhydramine 25mg 30 min before infusion reduces infusion reactions. Some patients also benefit from hydrocortisone 50mg IV for recurrent severe infusion reactions.","Aggressive potassium and magnesium supplementation is the norm, not the exception. Patients on full-dose L-AmB may need 40-100 mEq KCl/day to maintain normokalemia — this is drug-induced renal tubular loss.","For cryptococcal meningitis induction: L-AmB 4-6 mg/kg/day + flucytosine 100 mg/kg/day × 2 weeks is the gold standard (WHO-endorsed). After induction, consolidate with fluconazole 400mg/day × 8 weeks, then maintenance 200mg/day.","Mucormycosis requires HIGH-DOSE L-AmB (5-10 mg/kg/day) — the MIC for Mucorales is significantly higher than for Candida/Aspergillus. Standard doses (3 mg/kg) are subtherapeutic for mucormycosis.","ABCD, ABLC, L-AmB are all lipid-associated formulations but they are NOT interchangeable. AmBisome (L-AmB) is a true liposomal formulation with the best safety data. ABLC (Abelcet) and ABCD (Amphotec) have different toxicity profiles."],dosingByIndication:[{label:"Cryptococcal, mold, or resistant Candida CNS/deep infection",regimen:"3-5 mg/kg IV q24h",notes:"Use the higher end when CNS disease, severe mold infection, or salvage therapy is the reason you chose amphotericin."},{label:"Mucormycosis",regimen:"5-10 mg/kg IV q24h",notes:"High-dose therapy is the rule for mucormycosis, not an exception."}],renalReplacement:[{modality:"HD",guidance:"No supplemental dosing is needed because the drug is not meaningfully removed by hemodialysis, but HD does not protect the kidneys from amphotericin toxicity."},{modality:"CRRT",guidance:"Dose is usually unchanged in CRRT; daily renal and electrolyte review matters more than the machine settings."}],specialPopulations:[{population:"Pregnancy",guidance:"Liposomal amphotericin B remains the preferred systemic antifungal for many serious infections in pregnancy."},{population:"Concurrent nephrotoxins or baseline CKD",guidance:"Pre-hydration, electrolyte replacement, and daily renal review matter more than nominal dose adjustment because toxicity is exposure-limiting."}],therapeuticDrugMonitoring:{target:"No routine serum target; the actionable endpoints are renal stability, potassium and magnesium replacement, and clinical response.",sampling:"No drug levels are standard. Follow BMP daily, especially creatinine, potassium, magnesium, and bicarbonate.",adjustment:"If nephrotoxicity becomes limiting, decide whether the pathogen/site allows step-down to a safer azole rather than just stretching the interval."},administration:{infusion:"Usually infused over about 2 hours; do not give as IV push.",compatibility:"Use a dedicated line when possible and avoid mixing with saline-containing solutions in the same bag.",note:"Pre-hydration and standing electrolyte replacement should be part of the regimen, not optional add-ons."},ivToPoSwitch:{poBioavailability:"No oral amphotericin formulation provides systemic treatment.",switchCriteria:"Transition only when the pathogen, site, and susceptibility profile support a safer oral azole or other active step-down agent.",note:"For cryptococcal and mucormycosis pathways, the step-down clock is determined by induction milestones and source control, not by simple clinical improvement."},interactionActions:[{interactingAgent:"Other nephrotoxins such as tacrolimus, vancomycin, aminoglycosides, or IV contrast",effect:"Additive kidney injury can make amphotericin toxicity arrive earlier and more severely.",management:"Remove avoidable nephrotoxins and increase lab frequency when combination exposure is unavoidable.",severity:"major"},{interactingAgent:"Digoxin",effect:"Amphotericin-driven hypokalemia can potentiate digoxin toxicity.",management:"Replace potassium aggressively and monitor digoxin effect closely.",severity:"major"}],stewardshipUseCases:[{scenario:"Bridge for severe mold, cryptococcal, or resistant Candida infection",role:"The broad fungicidal fallback when site, resistance, or pregnancy makes azoles or echinocandins inadequate.",notes:"The stewardship goal is to leave amphotericin as soon as a safer active option becomes appropriate."},{scenario:"Suspected mucormycosis",role:"High-dose liposomal amphotericin B is the default anchor while diagnosis and surgical plans are still forming.",notes:"Do not substitute voriconazole when Mucorales remains on the table."}],penetration:[{site:"Reticuloendothelial / deep tissue sites",detail:"Broad tissue distribution is one reason liposomal amphotericin B remains the fallback for severe mold and disseminated fungal disease."},{site:"CSF / brain",detail:"CNS entry is imperfect but clinically meaningful enough to support use in cryptococcal and mold CNS infection when paired with the right companion regimen."},{site:"Urine",detail:"Urinary concentrations are limited with the liposomal formulation, so lower-tract fungal infection may need another agent when susceptibility allows."}]}]};export{e as ADVANCED_AGENTS};
